function executeTeleport(target, normal) {
     if (player.energy < CONFIG.teleportCost) {
         AudioSys.playMiss();
         return;
     }
     player.energy -= CONFIG.teleportCost;

     // 1. Basic Target Calculation
     // Option 2: Apply Wall Offset to prevent physics clipping
     const dest = target.clone();
     let isWallHit = false;

     if (normal) {
         // Push away from surface to prevent getting stuck inside geometry
         // Increased to 0.8 to safely clear the player radius
         dest.addScaledVector(normal, 0.8); 

         // Detect if we hit a wall (vertical surface) vs floor/slope
         // If normal.y is near 0, it's a wall.
         if (Math.abs(normal.y) < 0.5) {
             isWallHit = true;
         }
     }

     // 2. Floor Anchor (The Void Fix)
     // Only snap to floor if we are NOT targeting a wall.
     // This allows teleporting high up walls without getting dragged down.
     if (!isWallHit) {
        snapToFloor(dest); 
     }

     const startInAir = !player.onGround;
     const groundAtTarget = getGroundHeight(dest.x, dest.z);
     const endInAir = (dest.y - (groundAtTarget + 1.6)) > 0.5;

     player.lastTeleportWasAerial = startInAir || endInAir;
     player.hasPhaseStruck = false; 

     spawnParticles(camera.position, 0x00ffaa, 20); 

     camera.position.copy(dest);
     // player.velocity.set(0,0,0); // This resets player velocity after teleport
     player.velocity.y = 2; // Slight hop
     player.jumpsRemaining = 1; 
     player.onGround = false; 

     // 3. Enable Phasing (Soft-Clip)
     player.isPhasing = true;
     player.phasingTimer = 0.2; // 200ms grace period

     if(!startInAir) {
         player.airTimeStart = performance.now();
     }

     player.lastTeleportTime = performance.now(); 

     AudioSys.playTeleport();
     spawnParticles(dest, 0x00ffaa, 30);
}

